const fileURL = $('FN - Seta Dados Entrada').item.json.fileURL;

const prompt = "Analise o documento financeiro e responda APENAS com JSON valido, sem markdown.

PASSO 1 - Identifique o tipo:
- "comprovante_simples": PIX, TED, DOC, transferencia, pagamento de boleto unico
- "cupom_fiscal": cupom/nota fiscal de mercado, supermercado, loja, com lista de produtos

PASSO 2 - Extraia conforme o tipo detectado:

Para comprovante_simples, retorne:
{
  "tipo_documento": "comprovante_simples",
  "data_transacao": "dd/MM/yyyy",
  "transacao": "descricao curta (ex: PIX para Joao, Pagamento fatura Nubank)",
  "categoria": "entrada ou saida",
  "valor": 0.00,
  "estabelecimento": null,
  "itens": []
}

Para cupom_fiscal, retorne:
{
  "tipo_documento": "cupom_fiscal",
  "data_transacao": "dd/MM/yyyy",
  "transacao": "Compra em [NOME_DO_ESTABELECIMENTO]",
  "categoria": "saida",
  "valor": 0.00,
  "estabelecimento": "nome da loja/mercado",
  "itens": [
    {
      "descricao": "nome do produto",
      "quantidade": 1,
      "valor_unitario": 0.00,
      "valor_total": 0.00
    }
  ]
}

Regras criticas:
- categoria: "entrada" se o titular RECEBEU o valor; "saida" se PAGOU ou COMPROU
- Cupons fiscais sao SEMPRE "saida"
- valor = total pago (numero puro, sem R$, sem + ou -)
- Se nao encontrar data, use null
- Valores numericos sem simbolos";

const requestBody = {
  model: "gpt-4o",
  messages: [
    {
      role: "system",
      content: "Voce e um extrator de dados de documentos financeiros. Analise o documento e extraia as informacoes. Responda APENAS com JSON valido, sem markdown, sem explicacoes."
    },
    {
      role: "user",
      content: [
        { type: "image_url", image_url: { url: fileURL } },
        { type: "text", text: prompt }
      ]
    }
  ],
  max_tokens: 1000
};

return [{ json: { requestBody: JSON.stringify(requestBody) } }];

