return [{ json: { requestBody: JSON.stringify(requestBody) } }];

const raw = $input.first().json;
let content = '';
try {
  content = raw.choices[0].message.content;
} catch (e1) {
  try {
    const msgBlock = raw.output.find(o => o.type === 'message');
    const textBlock = msgBlock.content.find(c => c.type === 'output_text');
    content = textBlock.text;
  } catch (e2) {
    throw new Error('Resposta Vision invalida: ' + JSON.stringify(raw).substring(0, 500));
  }
}

content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  throw new Error('JSON invalido: ' + content);
}

const categoriaRaw = (parsed.categoria || '').toLowerCase().trim();
const isEntrada = categoriaRaw.includes('entrada');
const valor = parseFloat(parsed.valor) || 0;
const tipoDoc = parsed.tipo_documento || 'comprovante_simples';
const itens = parsed.itens || [];

// Sanitizar categoria: nunca deixar direção como categoria semântica
const categoriasInvalidas = ['entrada', 'saida', 'saída', 'gasto', 'despesa', 'receita', 'debito', 'débito', 'credito', 'crédito'];
const categoriaSanitizada = (() => {
  if (categoriasInvalidas.includes(categoriaRaw)) {
    const ref = ((parsed.estabelecimento || '') + ' ' + (parsed.transacao || '')).toLowerCase();
    if (ref.match(/farm|drog|medic|saude|saúde|hospital|clinic|plano/)) return 'Saúde';
    if (ref.match(/mercado|superm|hortifrut|açougue|padaria|cafe|café/)) return 'Alimentação';
    if (ref.match(/restaur|lanche|pizza|burger|ifood|delivery|sushi/)) return 'Alimentação';
    if (ref.match(/uber|99|taxi|táxi|posto|gasolina|combustiv|shell|ipiranga/)) return 'Transporte';
    if (ref.match(/escola|facul|curso|mensalidade|colegio|colégio/)) return 'Educação';
    if (ref.match(/aluguel|condomin|energia|agua|água|internet|luz|gas|gás/)) return 'Moradia';
    if (ref.match(/amazon|shopee|magazine|americanas|casas bahia|lojas/)) return 'Compras';
    if (ref.match(/netflix|spotify|amazon prime|disney|hbo|streaming/)) return 'Assinaturas';
    if (ref.match(/salario|salário|pagamento recebido|transferencia recebida/)) return 'Salário';
    return 'Outros';
  }
  return categoriaRaw.charAt(0).toUpperCase() + categoriaRaw.slice(1);
})();

let itensFormatados = '';
if (itens.length > 0) {
  itensFormatados = itens
    .map(i => '  \u2022 ' + i.descricao + ' (' + i.quantidade + 'x) \u2014 R$ ' + parseFloat(i.valor_total).toFixed(2))
    .join('\n');
}

return [{
  json: {
    tipo_documento: tipoDoc,
    data_transacao: parsed.data_transacao || new Date().toLocaleDateString('pt-BR'),
    transacao: parsed.transacao || 'Comprovante financeiro',
    estabelecimento: parsed.estabelecimento || null,
    categoria: categoriaSanitizada,
    entrada: isEntrada ? valor : 0,
    saida: isEntrada ? 0 : valor,
    itens: itens,
    itens_formatados: itensFormatados,
    tem_itens: itens.length > 0
  }
}];

